\text{Average} &= \frac{a + b + c}{3},\\
&= \frac{(14 - 2b) + b + (b + 1)}{3},\\
&= \frac{14 - 2b + b + b + 1}{3},\\
&= \frac{15}{3},\\
&= 5.
\end{align*}
